import { useState } from 'react';
import {BrowserRouter as Router, Routes, Route} from 'react-router-dom'
import axios from 'axios';
import Home from '../pages/Home'
import '../App.css';

const api = axios.create({baseURL: 'http://localhost:5000'});

function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [messageType, setMessageType] = useState('');

  const showMessage = (text, type) => {
    setMessage(text);
    setMessageType(type);
    setTimeout(() => {
      setMessage('');
      setMessageType('');
    }, 5000);
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');
    setMessageType('');

    try {
      const response = await api.post('/login', form);

      if (response.status === 200) {
        setIsLoggedIn(true);
        showMessage(`${response.data.message}`, 'success');
        setForm({ login: '', password: '' });
      }
    } catch (error) {
      if (error.response) {
        showMessage(`${error.response.data.message}`, 'error');
      } else {
        showMessage('Ошибка соединения с сервером', 'error');
      }
      setIsLoggedIn(false);
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value
    }));
  };

  if (isLoggedIn) {
    return (
      <Router>
        <Routes>
          <Route path="/" element={<Home />} />
        </Routes>
      </Router>
    );
  }

  return (
    <div className="app-container">
      <div className="app-card">
        <h2 className="app-title">Вход в систему</h2>
        <p className="app-subtitle">Введите логин и пароль</p>

        {message && (
          <div className={`message ${messageType}-message`}>
            {message}
          </div>
        )}

        <form onSubmit={handleLogin} className="app-form">
          <div className="form-group">
            <input
              type="text"
              name="login"
              value={form.login}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Логин"
              required
              disabled={loading}
              autoComplete="username"
            />
          </div>

          <div className="form-group">
            <input
              type="password"
              name="password"
              value={form.password}
              onChange={handleInputChange}
              className="form-input"
              placeholder="Пароль"
              required
              disabled={loading}
              autoComplete="current-password"
            />
          </div>

          <button 
            type="submit" 
            className="login-button"
            disabled={loading || !form.login || !form.password}
          >
            {loading ? (
              <>
                <span className="spinner"></span>
                Вход...
              </>
            ) : 'Войти'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default Login;
